import React from 'react'

function Homescreen() {
    return (
    
        <div className="App">
          <Navbar />
          <BrowserRouter>
            <Routes>
            <Route path='/home' exact element={<HomeScreen />}/>
            </Routes>
          </BrowserRouter>
        </div>
        
      );
}

export default Homescreen
